2284	122	impl LoadTestResults	impl	LoadTestResults	\N	163	250	impl LoadTestResults {\n    fn new() -> Self {\n        Self {\n            total_queries: 0,\n            successful_queries: 0,\n            failed_queries: 0,\n            duration: Duration::from_secs(0),\n            latencies_ms: Vec::new(),\n        }\n    }\n\n    fn add_result(&mut self, result: QueryResult) {\n        self.total_queries += 1;\n        if result.success {\n            self.successful_queries += 1;\n            self.latencies_ms.push(result.latency_ms);\n        } else {\n            self.failed_queries += 1;\n        }\n    }\n\n    fn calculate_percentile(&self, percentile: f64) -> f64 {\n        if self.latencies_ms.is_empty() {\n            return 0.0;\n        }\n        let mut sorted = self.latencies_ms.clone();\n        sorted.sort_by(|a, b| a.partial_cmp(b).unwrap());\n        let index = ((sorted.len() as f64 - 1.0) * percentile) as usize;\n        sorted[index]\n    }\n\n    fn p50(&self) -> f64 {\n        self.calculate_percentile(0.50)\n    }\n\n    fn p95(&self) -> f64 {\n        self.calculate_percentile(0.95)\n    }\n\n    fn p99(&self) -> f64 {	'0':13,16,19,24 '0.0':62 '0.50':92 '0.95':99 '1':38,43,50 '1.0':80 'a':69 'a.partial':71 'add':30 'as':78,82 'b':70,73 'by':68 'calculate':52 'cmp':72 'crates/maproom/tests/performance/load_test.rs':1 'duration':20,21 'else':47 'empty':60 'f64':56,57,79,89,96,103 'failed':17 'fn':7,29,51,86,93,100 'from':22 'if':39,58 'impl':2,5 'index':76,85 'latencies':25 'let':63,75 'loadtestresults':3,4,6 'ms':26,46 'mut':32,64 'new':8,28 'p50':87 'p95':94 'p99':101 'percentile':53,55,81,91,98 'queries':12,15,18,37,42,49 'queryresult':35 'result':31,34 'result.latency':45 'result.success':40 'return':61 'secs':23 'self':9,10,33,54,88,95,102 'self.calculate':90,97 'self.failed':48 'self.latencies_ms.clone':66 'self.latencies_ms.is':59 'self.latencies_ms.push':44 'self.successful':41 'self.total':36 'sorted':65,84 'sorted.len':77 'sorted.