8229	276	migrate_file	func	async fn (\n        &mut self,\n        file: &MarkdownFile,\n        stats: &mut MigrationStats,\n    ) -> Result<FileMigrationStats>	Migrate a single file	234	318	    async fn migrate_file(\n        &mut self,\n        file: &MarkdownFile,\n        stats: &mut MigrationStats,\n    ) -> Result<FileMigrationStats> {\n        // Start transaction\n        let tx = self.client.build_transaction().start().await?;\n\n        // Count old chunks\n        let old_count_row = tx\n            .query_one(\n                "SELECT COUNT(*) FROM maproom.chunks WHERE file_id = $1",\n                &[&file.id],\n            )\n            .await?;\n        let old_chunks: i64 = old_count_row.get(0);\n\n        // Parse with new parser\n        let new_chunks = parser::extract_chunks(&file.content, "md");\n\n        // Delete old chunks\n        tx.execute(\n            "DELETE FROM maproom.chunks WHERE file_id = $1",\n            &[&file.id],\n        )\n        .await\n        .context("Failed to delete old chunks")?;\n\n        // Insert new chunks\n        let mut inserted_count = 0;\n        for chunk in &new_chunks {\n            let preview = Self::extract_preview(&file.content, chunk.start_line, chunk.end_line);\n            let ts_doc = Self::build_ts_doc(&file.relpath, chunk, &preview);\n\n            // Insert chunk directly in transaction\n            tx.query_one(\n                "INSERT INTO maproom.chunks (\n                   file_id, symbol_name, kind, signature, docstring, start_line, end_line, preview, ts_doc, recency_score, churn_score, metadata\n                 ) VALUES (\n                   $1, $2::text, ($3::text)::maproom.symbol_kind, $4::text, $5::text, $6, $7, $8::text, to_tsvector('simple', unaccent($9::text)), $10, $11, $12::jsonb	'0':63,102 '1':55,86,158 '10':179 '11':180 '12':181 '2':159 '3':161 '4':165 '5':167 '6':169 '7':170 '8':171 '9':177 'a':15 'async':4,18 'await':37,57,88 'build':122 'chunk':104,126,129 'chunk.end